// Autogenerated: provide window.ensureSupabase() singleton
(function(){
  let _clientPromise = null;

  function loadScriptOnce(src){
    return new Promise((resolve, reject) => {
      if (document.querySelector('script[data-autoload-supabase]')) {
        return resolve();
      }
      const s = document.createElement('script');
      s.src = src;
      s.async = true;
      s.defer = true;
      s.setAttribute('data-autoload-supabase','1');
      s.onload = () => resolve();
      s.onerror = (e) => reject(e);
      document.head.appendChild(s);
    });
  }

  window.ensureSupabase = async function ensureSupabase(){
    if (_clientPromise) return _clientPromise;

    _clientPromise = (async () => {
      const SV = window.SUPER_VARSAR || window.SUPABASE_VARS || {};
      if (!(SV && SV.url && SV.anonKey)) {
        throw new Error("Supabase vars missing: window.SUPER_VARSAR.url / anonKey");
      }
      // load supabase-js v2 from CDN if not present
      if (!window.supabase || !window.supabase.createClient) {
        await loadScriptOnce("https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2");
      }
      return window.supabase.createClient(SV.url, SV.anonKey);
    })();

    return _clientPromise;
  };

  // Optional health ping attaching for quick debug
  window.__supabaseHealthCheck = async function(){
    try{
      const c = await window.ensureSupabase();
      // version check (no-op call)
      return { ok:true };
    }catch(e){
      return { ok:false, error: String(e) };
    }
  }
})();